import sys,math

def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        n=int(next(it))
        a=[int(next(it)) for _ in range(n)]
        pre=[0]*n
        suf=[0]*n
        for i in range(n):
            pre[i]=a[i] if i==0 else math.gcd(pre[i-1],a[i])
        for i in range(n-1,-1,-1):
            suf[i]=a[i] if i==n-1 else math.gcd(suf[i+1],a[i])
        ans=0
        for i in range(n):
            if i==0:
                cur=suf[1]
            elif i==n-1:
                cur=pre[n-2]
            else:
                cur=math.gcd(pre[i-1],suf[i+1])
            if cur>ans:
                ans=cur
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    main()

