const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
function gcd(a,b){while(b!==0){let t=b;b=a%b;a=t;}return a;}
const T=Number(input[idx++]);
let outputs=[];
for(let tc=0;tc<T;++tc){
  const n=Number(input[idx++]);
  const a=new Array(n);
  for(let i=0;i<n;++i) a[i]=Number(input[idx++]);
  const pre=new Array(n);
  const suf=new Array(n);
  for(let i=0;i<n;++i){
    pre[i]= i===0? a[i]: gcd(pre[i-1], a[i]);
  }
  for(let i=n-1;i>=0;--i){
    suf[i]= i===n-1? a[i]: gcd(suf[i+1], a[i]);
  }
  let ans=0;
  for(let i=0;i<n;++i){
    let cur;
    if(i===0) cur=suf[1];
    else if(i===n-1) cur=pre[n-2];
    else cur=gcd(pre[i-1],suf[i+1]);
    if(cur>ans) ans=cur;
  }
  outputs.push(String(ans));
}
